const payment = $input.first().json;
const externalRef = payment.external_reference || '';
const parts = externalRef.split('_');
const whatsappFrom = parts[0] || '';
let workflowState = 'AWAITING_PAYMENT';
let responseMessage = '';

switch (payment.status) {
  case 'approved': 
    workflowState = 'PAYMENT_APPROVED'; 
    responseMessage = `🎉 *Pagamento confirmado!*

Seu laudo completo de precatórios será enviado para o seu e mail em até 24 horas. Lembre-se de verificar também a caixa de spam.

Em casos de processos físicos scaneados ou que apresentem problemas de configuração, o prazo poderá ser prorrogado em até 7 dias úteis, em razão da dificuldade de leitura dos documentos.

Digite menu para voltar ao início.`; 
    break;

  case 'rejected': 
    workflowState = 'PAYMENT_REJECTED'; 
    responseMessage = `❌ *Pagamento não aprovado.*

Digite "sim" para gerar um novo link.`; 
    break;

  case 'pending': 
  case 'in_process': 
    workflowState = 'PAYMENT_PENDING'; 
    responseMessage = `⏳ *Pagamento em análise.*

Digite menu para voltar ao início.`; 
    break;

  default: 
    return [];
}

return [{
  json: {
    payment_id: payment.id, 
    status: payment.status, 
    amount: payment.transaction_amount, 
    whatsapp_from: whatsappFrom, 
    external_reference: externalRef, 
    workflow_state: workflowState, 
    response_message: responseMessage
  }
}];

